import{_ as a,o as i,c as e,ai as l}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"macOS 权限","description":"","frontmatter":{"read_when":["调试缺失或卡住的 macOS 权限提示","打包或签名 macOS 应用","更改 Bundle ID 或应用安装路径"],"summary":"macOS 权限持久化（TCC）和签名要求","title":"macOS 权限","x-i18n":{"generated_at":"2026-02-01T21:32:58Z","model":"claude-opus-4-5","provider":"pi","source_hash":"d012589c0583dd0b3792d695f3f71a6ff265704cf02a3b79f8c4a5b14712e6aa","source_path":"platforms/mac/permissions.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/permissions.md","filePath":"zh-CN/platforms/mac/permissions.md","lastUpdated":1771906665000}'),n={name:"zh-CN/platforms/mac/permissions.md"};function t(p,s,r,c,h,d){return i(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="macos-权限-tcc" tabindex="-1"><a class="header-anchor" href="#macos-权限-tcc">#</a> macOS 权限（TCC）</h1><p>macOS 权限授予是脆弱的。TCC 将权限授予与应用的代码签名、Bundle 标识符和磁盘路径关联。如果其中任何一项发生变化，macOS 会将该应用视为新应用，可能会丢弃或隐藏权限提示。</p><h2 id="稳定权限的要求" tabindex="-1"><a class="header-anchor" href="#稳定权限的要求">#</a> 稳定权限的要求</h2><ul><li>相同路径：从固定位置运行应用（对于 OpenSoul，为 <code>dist/OpenSoul.app</code>）。</li><li>相同 Bundle 标识符：更改 Bundle ID 会创建新的权限身份。</li><li>已签名的应用：未签名或临时签名的构建不会持久化权限。</li><li>一致的签名：使用真实的 Apple Development 或 Developer ID 证书，以确保签名在多次构建之间保持稳定。</li></ul><p>临时签名每次构建都会生成新的身份。macOS 会忘记之前的授权，提示可能完全消失，直到清除过期条目为止。</p><h2 id="权限提示消失时的恢复清单" tabindex="-1"><a class="header-anchor" href="#权限提示消失时的恢复清单">#</a> 权限提示消失时的恢复清单</h2><ol><li>退出应用。</li><li>在系统设置 -&gt; 隐私与安全性中移除该应用条目。</li><li>从相同路径重新启动应用并重新授予权限。</li><li>如果提示仍未出现，使用 <code>tccutil</code> 重置 TCC 条目后重试。</li><li>某些权限仅在完全重启 macOS 后才会重新出现。</li></ol><p>重置示例（根据需要替换 Bundle ID）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Accessibility</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai.opensoul.mac</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ScreenCapture</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai.opensoul.mac</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AppleEvents</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果你正在测试权限，请始终使用真实证书签名。临时签名的构建仅适用于不需要权限的快速本地运行。</p>`,10)])])}const k=a(n,[["render",t]]);export{m as __pageData,k as default};
